!function(){"use strict";function t(){var t=document.querySelectorAll(".promo-countdown[data-end]");if(t.length)for(var e=Math.floor(Date.now()/1e3),o=0;o<t.length;o++){var a=t[o],n=parseInt(a.getAttribute("data-end"),10);if(n){var r=n-e,d=a.querySelector(".cd-text");if(d)if(r<=0)d.textContent="Promoção encerrada!",a.style.opacity="0.5",a.dataset.expired||(a.dataset.expired="1",setTimeout(function(){location.reload()},3e3));else if(r<60)d.textContent="Últimos segundos!";else if(r<3600){var i=Math.floor(r/60);d.textContent="Acaba em "+i+"min"}else if(r<86400){var l=Math.floor(r/3600),c=Math.floor(r%3600/60);d.textContent="Acaba em "+l+"h"+(c>0?" "+c+"min":"")}else{var f=Math.floor(r/86400),s=Math.floor(r%86400/3600);d.textContent=1===f?"Só até amanhã!":"Acaba em "+f+"d "+s+"h"}}}}"loading"===document.readyState?document.addEventListener("DOMContentLoaded",function(){t(),setInterval(t,3e4)}):(t(),setInterval(t,3e4))}();